queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?typeofproperty WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProperties ?child ; p:hasLand_Trusts ?parent . } GROUP BY ?child }
  ?child p:typeOfProperty ?typeofproperty .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Land_Trusts } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?typeofproperty WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProperties ?child ; p:hasLand_Trusts ?parent . } GROUP BY ?child }
  ?child p:typeOfProperty ?typeofproperty .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Land_Trusts } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?trustname ?typeofproperty WHERE {
  ?land_trusts_properties a :Land_Trusts_Properties .
  ?properties a :Properties .
  ?land_trusts_properties p:hasProperties ?properties .
  ?land_trusts a :Land_Trusts .
  ?land_trusts_properties p:hasLand_Trusts ?land_trusts .
  ?land_trusts p:trustName ?trustname .
  ?properties p:typeOfProperty ?typeofproperty .
} }
}
